/**
 * Validate and normalize the incoming reply notification.
 * Real-world this could come from email-parsing services (Mailparser, Zapier-Email-Parser),
 * inbound webhooks from email providers (SendGrid, Mailgun), or HubSpot's own reply tracking.
 * For demo we accept a simple shape and normalize.
 */

const body = $input.first().json.body || $input.first().json;

const email = (body.email || body.from || body.sender || '').toString().trim().toLowerCase();
const replyAt = body.replied_at || body.timestamp || new Date().toISOString();
const excerpt = (body.excerpt || body.message_preview || body.body || '').toString().slice(0, 500);
const channel = body.channel || 'email';

if (!email) {
  return {
    json: {
      _valid: false,
      _error: 'reply payload missing email/from/sender',
      _ingested_at: new Date().toISOString()
    }
  };
}

return {
  json: {
    _valid: true,
    email,
    replied_at: replyAt,
    excerpt,
    channel,
    _request_id: 'reply_' + Date.now().toString(36) + '_' + Math.random().toString(36).slice(2, 8),
    _ingested_at: new Date().toISOString()
  }
};

